-- Seed wine geography data
DELETE FROM public.wine_appellations;
DELETE FROM public.wine_sub_regions;
DELETE FROM public.wine_regions;
DELETE FROM public.wine_countries;

DO $$
DECLARE
  v_user_id uuid;
  v_country_id uuid;
  v_region_id uuid;
  v_sub_id uuid;
BEGIN
  v_user_id := COALESCE(
    (SELECT user_id FROM public.wine_countries LIMIT 1),
    (SELECT id FROM auth.users LIMIT 1)
  );
  IF v_user_id IS NULL THEN
    RAISE NOTICE 'No user found; skipping seed.';
    RETURN;
  END IF;

